Add an `errors` object to your state:

```jsx
const [form, setForm] = useState({ email: '', password: '' });
const [errors, setErrors] = useState({});

const validate = () => {
  const newErrors = {};
  if (!form.email.includes('@')) {
    newErrors.email = 'Email must contain @';
  }
  if (form.password.length < 6) {
    newErrors.password = 'Password must be at least 6 characters';
  }
  setErrors(newErrors);
  return Object.keys(newErrors).length === 0; // true if valid
};

const handleSubmit = () => {
  if (validate()) {
    // submit
  }
};
```

Show errors near the input:

```jsx
<View>
  <TextInput
    value={form.email}
    onChangeText={text => setForm({ ...form, email: text })}
    style={[styles.input, errors.email && styles.errorInput]}
  />
  {errors.email && <Text style={styles.errorText}>{errors.email}</Text>}
</View>
```

Style the input border red when error exists, and show a message.

## Validate on Blur or Change

You might want to clear an error as soon as the user fixes it. Use `onBlur` to trigger validation for that field only.

```jsx
const validateField = (field, value) => {
  // perform specific validation
  if (field === 'email' && !value.includes('@')) {
    setErrors(prev => ({ ...prev, email: 'Invalid email' }));
  } else {
    setErrors(prev => ({ ...prev, email: undefined }));
  }
};

<TextInput
  value={form.email}
  onChangeText={text => {
    setForm({ ...form, email: text });
    // optionally validate on change (be careful with performance)
  }}
  onBlur={() => validateField('email', form.email)}
/>
```
